import { jsx } from 'react/jsx-runtime';

const RatingItem = ({ index, children, onChange, ...props }) => (jsx("div", { role: "button", tabIndex: onChange ? 0 : undefined, className: "dsb_rating__select__item", ...props, onClick: () => {
        onChange?.(index);
    }, onKeyDown: onChange
        ? event => {
            if (event.key === 'Enter' || event.key === ' ') {
                event.preventDefault();
                onChange?.(index);
            }
        }
        : undefined, children: children }));

export { RatingItem };
